INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'gn', 1, 26, NULL, 'John Owen', 'A imagem de Deus no homem é o ápice da criação. Owen destaca domínio e responsabilidade. O homem representa Deus na criação. Aplicação: Exerça seu domínio com sabedoria.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'gn', 3, 15, NULL, 'João Calvino', 'O proto-evangelho promete a semente que esmaga a serpente. Calvino vê aqui a primeira proclamação do evangelho. Cristo vence Satanás. Aplicação: Confie na vitória de Cristo.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'gn', 12, 1, NULL, 'Thomas Watson', 'Abram sai por fé obedecendo ao chamado divino. Watson observa a fé operando em separação. Aplicação: A fé obedece mesmo sem ver o caminho.', 'Thomas Watson', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'gn', 15, 6, NULL, 'João Calvino', 'Justificação pela fé antes da circuncisão. Calvino mostra que a promessa precede a lei. Aplicação: A justiça vem somente pela fé.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'gn', 22, 8, NULL, 'Martinho Lutero', 'Deus proverá o cordeiro do holocausto. Lutero vê a fé em providência divina. O cordeiro prefigura Cristo. Aplicação: Confie que Deus proverá em toda provação.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'gn', 32, 28, NULL, 'João Calvino', 'Transformação pela luta com Deus. Calvino interpreta Israel como príncipe com Deus. Aplicação: Busque a Deus em luta espiritual.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'gn', 50, 20, NULL, 'John Owen', 'Providência divina transforma mal em bem. Owen vê Deus governando intenções humanas. Aplicação: Descanse na providência soberana.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'ex', 3, 14, NULL, 'João Calvino', 'Eu sou o que sou revela a autoexistência de Deus. Calvino vê a independência divina. Aplicação: Confie no Deus eterno e imutável.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'ex', 12, 13, NULL, 'Martinho Lutero', 'O sangue da páscoa protege da ira divina. Lutero vê figura de Cristo. Aplicação: Aplique o sangue de Cristo pela fé.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'ex', 14, 14, NULL, 'Charles Spurgeon', 'O Senhor pelejará por vós. Spurgeon vê ação divina vs descanso humano. Aplicação: Descanse no poder de Deus que peleja.', 'Charles Spurgeon', 'commentary', '#9333EA', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'ex', 20, 3, NULL, 'João Calvino', 'Primeiro mandamento: exclusividade de Deus. Calvino explica que bem-aventurança está em conhecer o único Deus. Aplicação: Coloque Deus absolutamente primeiro.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'ex', 33, 15, NULL, 'John Owen', 'A presença de Deus é essencial. Owen destaca que tudo é vazio sem Deus. Aplicação: Busque primeiro a presença divina.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'ex', 34, 6, NULL, 'John Bunyan', 'Deus é compassivo e clemente. Bunyan medita nos atributos divinos. Aplicação: Aproxime-se com confiança e temor.', 'John Bunyan', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'lv', 4, 20, NULL, 'John Owen', 'Expiação é necessária para perdão. Owen vê o sangue requerido pela justiça. Aplicação: Confie na expiação de Cristo.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'lv', 11, 44, NULL, 'Thomas Watson', 'Sede santos pois Eu sou santo. Watson destaca imitação de Deus como base da santidade. Aplicação: Busque santidade que imita a Deus.', 'Thomas Watson', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'lv', 17, 11, NULL, 'Martinho Lutero', 'A vida está no sangue. Lutero vê fundamento da expiação. Aplicação: Valorize o sangue de Cristo derramado.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'lv', 19, 2, NULL, 'João Calvino', 'Motivação para santidade baseada no caráter de Deus. Aplicação: Imite seu santo Deus.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'lv', 25, 10, NULL, 'Jerônimo', 'O jubileu é restauração divina. Jerônimo vê liberdade e terra retornando. Aplicação: Cristo é nosso jubileu de liberdade.', 'Jerônimo', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'nm', 6, 24, NULL, 'John Owen', 'A bênção sacerdotal: graça, proteção e paz. Owen vê três aspectos da graça divina. Aplicação: Receba a bênção em Cristo.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'nm', 14, 24, NULL, 'Martinho Lutero', 'Calebe teve outro espírito de fé. Lutero vê diferença entre fé e incredulidade. Aplicação: Siga o Senhor de coração inteiro.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'nm', 23, 19, NULL, 'Charles Spurgeon', 'Deus não é homem para mentir. Spurgeon medita na imutabilidade divina. Aplicação: Descanse nas promessas eternas.', 'Charles Spurgeon', 'commentary', '#9333EA', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'dt', 6, 4, NULL, 'Martinho Lutero', 'O Shema confessa a unidade de Deus. Lutero vê exclusão de toda idolatria. Aplicação: Ame a Deus de todo coração.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'dt', 8, 3, NULL, 'Thomas Watson', 'O homem não vive só de pão. Watson vê prioridade da Palavra de Deus. Aplicação: Alimente sua alma com a Palavra.', 'Thomas Watson', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'dt', 30, 6, NULL, 'João Calvino', 'Deus circuncidará seu coração. Calvino interpreta como regeneração divina. Aplicação: Peça a Deus que mude seu coração.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'js', 1, 8, NULL, 'Charles Spurgeon', 'Medite na lei dia e noite. Spurgeon vê sucesso espiritual dependendo da Escritura. Aplicação: Medite na Palavra constantemente.', 'Charles Spurgeon', 'commentary', '#9333EA', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES (gen_random_uuid(), 'js', 24, 15, NULL, 'John Owen', 'Escolhei hoje a quem servir. Owen medita na decisão irrevogável. Aplicação: Sirva somente ao Senhor.', 'John Owen', 'commentary', '#065F46', NOW());
